package org.apache.camel.component.fix;

import org.apache.camel.spi.Metadata;

/**
 * Constants for FIX protocol message headers.
 */
public final class FixConstants {

    @Metadata(description = "The FIX message type (e.g. D for NewOrderSingle, 8 for ExecutionReport).",
              javaType = "java.lang.String")
    public static final String FIX_MESSAGE_TYPE = "CamelFixMessageType";

    @Metadata(description = "The FIX session ID in the form BeginString:SenderCompID->TargetCompID.",
              javaType = "java.lang.String")
    public static final String FIX_SESSION_ID = "CamelFixSessionID";

    @Metadata(description = "The SenderCompID field value from the FIX message.",
              javaType = "java.lang.String")
    public static final String FIX_SENDER_COMP_ID = "CamelFixSenderCompID";

    @Metadata(description = "The TargetCompID field value from the FIX message.",
              javaType = "java.lang.String")
    public static final String FIX_TARGET_COMP_ID = "CamelFixTargetCompID";

    private FixConstants() {
    }
}

