package org.apache.camel.component.fix;

import org.apache.camel.spi.Metadata;
import org.apache.camel.spi.UriParam;
import org.apache.camel.spi.UriParams;

/**
 * Configuration for the FIX component.
 */
@UriParams
public class FixConfiguration {

    @UriParam(description = "Path to the QuickFIX/J configuration file.")
    private String configFile;

    @UriParam(description = "The SenderCompID identifying this FIX session.")
    @Metadata(required = true)
    private String senderCompID;

    @UriParam(description = "The TargetCompID identifying the counterparty FIX session.")
    @Metadata(required = true)
    private String targetCompID;

    @UriParam(defaultValue = "FIX.4.4", description = "The FIX protocol version (e.g. FIX.4.2, FIX.4.4, FIXT.1.1).")
    private String fixVersion = "FIX.4.4";

    @UriParam(defaultValue = "30", description = "Heartbeat interval in seconds.")
    private int heartBeatInterval = 30;

    @UriParam(description = "The hostname or IP address of the FIX counterparty to connect to (initiator mode).")
    private String socketConnectHost;

    @UriParam(description = "The port of the FIX counterparty to connect to (initiator mode).")
    private int socketConnectPort;

    public String getConfigFile() {
        return configFile;
    }

    /**
     * Path to the QuickFIX/J configuration file. When set, the file is used to configure the FIX session and other
     * parameters are ignored.
     */
    public void setConfigFile(String configFile) {
        this.configFile = configFile;
    }

    public String getSenderCompID() {
        return senderCompID;
    }

    /**
     * The SenderCompID (tag 49) identifying this end of the FIX session.
     */
    public void setSenderCompID(String senderCompID) {
        this.senderCompID = senderCompID;
    }

    public String getTargetCompID() {
        return targetCompID;
    }

    /**
     * The TargetCompID (tag 56) identifying the counterparty of the FIX session.
     */
    public void setTargetCompID(String targetCompID) {
        this.targetCompID = targetCompID;
    }

    public String getFixVersion() {
        return fixVersion;
    }

    /**
     * The FIX protocol version to use (e.g. FIX.4.2, FIX.4.4, FIXT.1.1).
     */
    public void setFixVersion(String fixVersion) {
        this.fixVersion = fixVersion;
    }

    public int getHeartBeatInterval() {
        return heartBeatInterval;
    }

    /**
     * The heartbeat interval in seconds. Controls how often heartbeat messages are sent.
     */
    public void setHeartBeatInterval(int heartBeatInterval) {
        this.heartBeatInterval = heartBeatInterval;
    }

    public String getSocketConnectHost() {
        return socketConnectHost;
    }

    /**
     * The hostname or IP address of the FIX acceptor to connect to when operating as an initiator.
     */
    public void setSocketConnectHost(String socketConnectHost) {
        this.socketConnectHost = socketConnectHost;
    }

    public int getSocketConnectPort() {
        return socketConnectPort;
    }

    /**
     * The TCP port of the FIX acceptor to connect to when operating as an initiator.
     */
    public void setSocketConnectPort(int socketConnectPort) {
        this.socketConnectPort = socketConnectPort;
    }
}

