package org.apache.camel.component.fix;

import org.apache.camel.AsyncCallback;
import org.apache.camel.Exchange;
import org.apache.camel.support.DefaultAsyncProducer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import quickfix.Message;
import quickfix.Session;
import quickfix.SessionID;
import quickfix.SessionNotFound;

/**
 * The FIX producer sends outbound FIX messages from Camel exchanges to a FIX session.
 */
public class FixProducer extends DefaultAsyncProducer {

    private static final Logger LOG = LoggerFactory.getLogger(FixProducer.class);

    public FixProducer(FixEndpoint endpoint) {
        super(endpoint);
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    public boolean process(Exchange exchange, AsyncCallback callback) {
        try {
            Message message = exchange.getIn().getMandatoryBody(Message.class);
            SessionID sessionId = resolveSessionID(exchange);

            LOG.debug("Sending FIX message to session {}", sessionId);

            boolean sent = Session.sendToTarget(message, sessionId);
            if (!sent) {
                exchange.setException(
                        new SessionNotFound("FIX session not found or message could not be sent: " + sessionId));
            }
        } catch (Exception e) {
            exchange.setException(e);
        } finally {
            callback.done(true);
        }
        return true;
    }

    // -----------------------------------------------------------------------
    // Helpers
    // -----------------------------------------------------------------------

    private SessionID resolveSessionID(Exchange exchange) {
        // Allow override via message header
        String sessionIdHeader = exchange.getIn().getHeader(FixConstants.FIX_SESSION_ID, String.class);
        if (sessionIdHeader != null) {
            return parseSessionID(sessionIdHeader);
        }

        // Fall back to endpoint session ID
        String sessionIDStr = getEndpoint().getSessionID();
        if (sessionIDStr != null) {
            return parseSessionID(sessionIDStr);
        }

        // Build from configuration
        FixConfiguration config = getEndpoint().getConfiguration();
        return new SessionID(config.getFixVersion(), config.getSenderCompID(), config.getTargetCompID());
    }

    private SessionID parseSessionID(String sessionIDStr) {
        if (sessionIDStr.contains(":") && sessionIDStr.contains("->")) {
            int colonIdx = sessionIDStr.indexOf(':');
            int arrowIdx = sessionIDStr.indexOf("->");
            String beginString = sessionIDStr.substring(0, colonIdx);
            String sender = sessionIDStr.substring(colonIdx + 1, arrowIdx);
            String target = sessionIDStr.substring(arrowIdx + 2);
            return new SessionID(beginString, sender, target);
        }
        throw new IllegalArgumentException(
                "Invalid FIX session ID format. Expected BeginString:SenderCompID->TargetCompID but got: " + sessionIDStr);
    }
}

