package org.apache.camel.component.fix;

import org.apache.camel.test.junit5.CamelTestSupport;
import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertInstanceOf;

public class FixComponentTest extends CamelTestSupport {

    @Test
    public void testComponentRegistered() {
        FixComponent component = context.getComponent("fix", FixComponent.class);
        assertNotNull(component, "FixComponent should be registered");
    }

    @Test
    public void testConfigurationDefaults() {
        FixConfiguration config = new FixConfiguration();
        assertEquals("FIX.4.4", config.getFixVersion());
        assertEquals(30, config.getHeartBeatInterval());
    }

    @Test
    public void testConstants() {
        assertEquals("CamelFixMessageType", FixConstants.FIX_MESSAGE_TYPE);
        assertEquals("CamelFixSessionID", FixConstants.FIX_SESSION_ID);
        assertEquals("CamelFixSenderCompID", FixConstants.FIX_SENDER_COMP_ID);
        assertEquals("CamelFixTargetCompID", FixConstants.FIX_TARGET_COMP_ID);
    }

    @Test
    public void testEndpointCreation() throws Exception {
        FixEndpoint endpoint = (FixEndpoint) context.getEndpoint(
                "fix:FIX.4.4:SENDER->TARGET?senderCompID=SENDER&targetCompID=TARGET");
        assertNotNull(endpoint);
        assertInstanceOf(FixEndpoint.class, endpoint);
    }
}

