    84→
    85→        try {
    86→            if (action == null) {
    87→                throw new NoSuchHeaderException("The action is a required header", exchange, QdrantHeaders.ACTION);
    88→            }
    89→
    90→            return switch (action) {
    91→                case CREATE_COLLECTION -> createCollection(exchange, callback);
    92→                case DELETE_COLLECTION -> deleteCollection(exchange, callback);
    93→                case UPSERT -> upsert(exchange, callback);
    94→                case RETRIEVE -> retrieve(exchange, callback);
    95→                case DELETE -> delete(exchange, callback);
    96→                case SIMILARITY_SEARCH -> similaritySearch(exchange, callback);
    97→                case COLLECTION_INFO -> collectionInfo(exchange, callback);
