   119→        final List<Points.PointStruct> points = in.getMandatoryBody(List.class);
   120→
   121→        Points.UpsertPoints value = Points.UpsertPoints.newBuilder()
   122→                .setCollectionName(collection)
   123→                .addAllPoints(points)
   124→                .setWait(true)
   125→                .build();
   126→
   127→        call(
   128→                this.client.upsertAsync(value),
   129→                (r, t) -> {
   130→                    if (t != null) {
   131→                        exchange.setException(new QdrantActionException(QdrantAction.UPSERT, t));
   132→                    } else {
   133→                        in.setHeader(QdrantHeaders.OPERATION_ID, r.getOperationId());
   134→                        in.setHeader(QdrantHeaders.OPERATION_STATUS, r.getStatus().name());
   135→                        in.setHeader(QdrantHeaders.OPERATION_STATUS_VALUE, r.getStatus().getNumber());
   136→                    }
   137→
   138→                    callback.done(false);
   139→                });
