   148→        final List<Common.PointId> ids = in.getMandatoryBody(List.class);
   149→
   150→        call(
   151→                this.client.retrieveAsync(
   152→                        collection,
   153→                        ids,
   154→                        WithPayloadSelectorFactory.enable(in.getHeader(
   155→                                QdrantHeaders.INCLUDE_PAYLOAD,
   156→                                QdrantHeaders.DEFAULT_INCLUDE_PAYLOAD,
   157→                                boolean.class)),
