package org.apache.camel.component.fix;

import org.apache.camel.Exchange;
import org.apache.camel.Processor;
import org.apache.camel.support.DefaultConsumer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import quickfix.Application;
import quickfix.DoNotSend;
import quickfix.FieldNotFound;
import quickfix.IncorrectDataFormat;
import quickfix.IncorrectTagValue;
import quickfix.Message;
import quickfix.RejectLogon;
import quickfix.Session;
import quickfix.SessionID;
import quickfix.SessionSettings;
import quickfix.SocketAcceptor;
import quickfix.UnsupportedMessageType;
import quickfix.field.MsgType;
import quickfix.field.SenderCompID;
import quickfix.field.TargetCompID;

/**
 * The FIX consumer receives inbound FIX messages and feeds them into Camel routes.
 */
public class FixConsumer extends DefaultConsumer implements Application {

    private static final Logger LOG = LoggerFactory.getLogger(FixConsumer.class);

    private SocketAcceptor acceptor;

    public FixConsumer(FixEndpoint endpoint, Processor processor) {
        super(endpoint, processor);
    }

    @Override
    public FixEndpoint getEndpoint() {
        return (FixEndpoint) super.getEndpoint();
    }

    @Override
    protected void doStart() throws Exception {
        super.doStart();

        FixConfiguration config = getEndpoint().getConfiguration();
        SessionSettings settings = buildSessionSettings(config);

        quickfix.DefaultMessageFactory messageFactory = new quickfix.DefaultMessageFactory();
        quickfix.FileStoreFactory storeFactory = new quickfix.FileStoreFactory(settings);
        quickfix.ScreenLogFactory logFactory = new quickfix.ScreenLogFactory(settings);

        acceptor = new SocketAcceptor(this, storeFactory, settings, logFactory, messageFactory);
        acceptor.start();

        LOG.info("FIX acceptor started for session {}", getEndpoint().getSessionID());
    }

    @Override
    protected void doStop() throws Exception {
        if (acceptor != null) {
            acceptor.stop();
            acceptor = null;
            LOG.info("FIX acceptor stopped for session {}", getEndpoint().getSessionID());
        }

        super.doStop();
    }

    // -----------------------------------------------------------------------
    // QuickFIX/J Application callbacks
    // -----------------------------------------------------------------------

    @Override
    public void onCreate(SessionID sessionId) {
        LOG.debug("FIX session created: {}", sessionId);
    }

    @Override
    public void onLogon(SessionID sessionId) {
        LOG.info("FIX session logged on: {}", sessionId);
    }

    @Override
    public void onLogout(SessionID sessionId) {
        LOG.info("FIX session logged out: {}", sessionId);
    }

    @Override
    public void toAdmin(Message message, SessionID sessionId) {
        // no-op: admin messages sent by the engine
    }

    @Override
    public void fromAdmin(Message message, SessionID sessionId)
            throws FieldNotFound, IncorrectDataFormat, IncorrectTagValue, RejectLogon {
        // no-op: admin messages received from counterparty
    }

    @Override
    public void toApp(Message message, SessionID sessionId) throws DoNotSend {
        // no-op: application messages sent by this endpoint
    }

    @Override
    public void fromApp(Message message, SessionID sessionId)
            throws FieldNotFound, IncorrectDataFormat, IncorrectTagValue, UnsupportedMessageType {
        Exchange exchange = createExchange(false);
        try {
            String msgType = message.getHeader().getString(MsgType.FIELD);
            String sender = message.getHeader().getString(SenderCompID.FIELD);
            String target = message.getHeader().getString(TargetCompID.FIELD);

            exchange.getIn().setHeader(FixConstants.FIX_MESSAGE_TYPE, msgType);
            exchange.getIn().setHeader(FixConstants.FIX_SESSION_ID, sessionId.toString());
            exchange.getIn().setHeader(FixConstants.FIX_SENDER_COMP_ID, sender);
            exchange.getIn().setHeader(FixConstants.FIX_TARGET_COMP_ID, target);
            exchange.getIn().setBody(message);

            getProcessor().process(exchange);
